const c=(t,r="")=>{if(!t)return`${(r||"").replace(/\/+$/,"")}/api`;if(t.startsWith("http")||t.startsWith("//"))return t;const e=(r||"").replace(/\/+$/,""),s=t.startsWith("/")?t:`/${t}`;return`${e}/api${s}`},a=(t,r="")=>{if(!t)return r||"/";if(t.startsWith("http")||t.startsWith("//"))return t;const e=r.replace(/\/+$/,""),s=t.startsWith("/")?t:`/${t}`;return`${e}${s}`},i=(t,r="")=>{if(!t)return"";if(t.startsWith("http")||t.startsWith("//")||t.startsWith("blob:"))return t;const e=(r||"").replace(/\/+$/,""),s=t.replace(/^\/+/,""),n=s.startsWith("storage/")?s:`storage/${s}`;return`${e}/${n}`};export{c as a,a as r,i as s};
